const rows = [];
for (const item of $input.all()) {
  const d = item.json || {};
  const likes = Number(d.likesCount) || 0;
  const comments = Number(d.commentsCount) || 0;
  const plays = Number(d.videoPlayCount) || Number(d.videoViewCount) || 0;
  const dur = d.videoDuration || "";
  const likeScore = Math.min(50, likes / 500000 * 50);
  const commentScore = Math.min(30, comments / 5000 * 30);
  const playScore = Math.min(20, plays / 2000000 * 20);
  const score = Math.round(likeScore + commentScore + playScore);
  const hashtags = Array.isArray(d.hashtags) ? d.hashtags.join(" ") : (d.hashtags || "");
  rows.push({ json: {
    engagement_score: score,
    owner_username: d.ownerUsername || "",
    owner_full_name: d.ownerFullName || "",
    post_type: d.type || "",
    likes_count: likes,
    comments_count: comments,
    video_play_count: plays,
    video_duration: dur,
    caption: (d.caption || "").slice(0, 300),
    hashtags: hashtags,
    short_code: d.shortCode || "",
    post_url: d.url || "",
    input_url: d.inputUrl || "",
    timestamp: d.timestamp || "",
    display_url: d.displayUrl || "",
    product_type: d.productType || "",
    is_verified_owner: (d.owner && d.owner.is_verified) ? "yes" : "no"
  }});
}
rows.sort((a, b) => b.json.engagement_score - a.json.engagement_score);
rows.forEach((r, i) => { r.json.rank = i + 1; });
return rows;

const item = $input.first();
if (item.binary && item.binary.data) { item.binary.data.fileName = "instagram-posts.xlsx"; }
return item;

const rows = $input.first().json.data || [];
const arr = Array.isArray(rows) ? rows : [];
const total = arr.length;
const totalLikes = arr.reduce((s, r) => s + (Number(r.likes_count) || 0), 0);
const totalComments = arr.reduce((s, r) => s + (Number(r.comments_count) || 0), 0);
const top = arr.slice(0, 10);
const rowsHtml = top.map((r, i) => '<tr><td>'+(i+1)+'</td><td>'+(r.owner_username||"")+'</td><td>'+(r.post_type||"")+'</td><td>'+(Number(r.likes_count)||0).toLocaleString()+'</td><td>'+(Number(r.comments_count)||0).toLocaleString()+'</td><td>'+(r.short_code||"")+'</td></tr>').join("");
const html = '<h2>Instagram Posts Report</h2><p><b>'+total+'</b> posts scraped. <b>'+totalLikes.toLocaleString()+'</b> total likes, <b>'+totalComments.toLocaleString()+'</b> total comments.</p><table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:13px;"><thead><tr style="background:#f0f0f0"><th>#</th><th>Author</th><th>Type</th><th>Likes</th><th>Comments</th><th>Shortcode</th></tr></thead><tbody>'+rowsHtml+'</tbody></table><p style="color:#666;font-size:12px;margin-top:16px;">Full dataset attached as instagram-posts.xlsx. Generated by CoreClaw + n8n.</p>';
return [{ json: { html, total, totalLikes, totalComments } }];
